#[test]
fn num_id_value_under_32_chars_opens_clean_and_numbers() {
    // 10-digit numId (1234567890) is well within Word's 32-char cap and must
    // bind normally: open clean, and accept-all yields exactly the body text.
    let numbering = "<?xml version=\"1.0\" encoding=\"UTF-8\" standalone=\"yes\"?>\n<w:numbering xmlns:w=\"http://schemas.openxmlformats.org/wordprocessingml/2006/main\"><w:abstractNum w:abstractNumId=\"0\"><w:multiLevelType w:val=\"singleLevel\"/><w:lvl w:ilvl=\"0\"><w:start w:val=\"1\"/><w:numFmt w:val=\"decimal\"/><w:lvlText w:val=\"%1.\"/><w:lvlJc w:val=\"start\"/></w:lvl></w:abstractNum><w:num w:numId=\"1234567890\"><w:abstractNumId w:val=\"0\"/></w:num></w:numbering>";
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1234567890"/></w:numPr></w:pPr><w:r><w:t>Numbered item.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);

    let report = validate(&b);
    assert!(
        report.ok,
        "MS-OI29500 §2.1.285 (ISO 29500-1 §17.9.15, §17.9.18): a 10-digit numId is well within Word's 32-char limit, \
         so the bound document must open clean (opensClean holds). validate() reported ok=false. issues={:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Numbered item.",
        "ISO 29500-1 §17.9.15: a numId reference matching a defined num binds the paragraph; the synthesized marker is \
         not body content, so accept-all yields exactly the paragraph run text. got={accepted:?}"
    );
}

